-- header-txt-color: #333333 ;
-- subheader-txt-color: rgb(var(--accent)) ;
-- misc-txt-color: #464646 ;
-- link-txt-color: #E6283C ;
-- link-hover-txt-color: white ;
/ * VARIABLES > Color Accents * /
-- accent: var(--acc-default) ;
-- acc-default: 59 , 59 , 59 ;
-- acc-wyoming: 142 , 0 , 18 ;
-- acc-canada: var(--acc-default) ;
-- acc-poland: 87 , 44 , 17 ;
-- acc-slothspit: 27 , 60 , 133 ;
-- acc-vanguard: 0 , 153 , 75 ;
-- acc-threshold: 121 , 113 , 130 ;
-- acc-overwatch: 28 , 37 , 56 ;
-- acc-spc: 0 , 165 , 200 ;
-- acc-fishing: 67 , 111 , 145 ;
-- acc-nightfall: 151 , 0 , 2 ;
-- acc-hybrasil: 27 , 60 , 133 ;
-- acc-goc: 39 , 84 , 149 ;
-- acc-spooky: 252 , 112 , 40 ;
/ * VARIABLES > BetterFootnotes * /
-- fnColor: var(--link-txt-color) ;
-- fnLinger: 1 s ;
} 
/ * VARIABLES > Info Bar * /
.info-container { 
-- barColour: rgb(var(--accent)) ;
-- linkColour: #EDEDED ;
} 
/ * MAIN * /
html { 
scroll-behavior: smooth ;
overflow-x: hidden ;
} 
body { 
font-family: var(--ui-font), sans-serif ;
font-size: var(--base-font-size) ;
color: rgb( 51 , 51 , 51 ) ;
background-image: linear-gradient(to bottom , #e0e0e0 , #fff 200 px ) ;
text-rendering: optimizeLegibility ;
overflow-wrap: break-word ;
} 
div#container-wrap { 
background: none ;
} 
#content-wrap { 
margin: 2 em auto 0 ;
} 
#page-content { 
font-family: var(--page-font), var(--ui-font), sans-serif ;
font-size: var(--page-font-size) ;
font-weight: 440 ;
} 
#page-content strong { 
font-weight: 700 ;
} 
tt ,
.page-source ,
pre ,
#edit-page-textarea { 
font-family: var(--mono-font) ;
} 
ol li { 
margin: 0 0 1 em ;
} 
ul { 
margin: 1 em 0 ;
} 
li ,
p { 
line-height: 1.5 ;
text-underline-offset: 40 % ;
} 
: :selection { 
background: rgb(var(--accent)) ;
color: #fff ;
} 
/ * Clicky links * /
a ,
a.newpage ,
a :visited ,
#side-bar a :visited { 
color: var(--link-txt-color) ;
} 
a :hover ,
a.newpage :hover ,
a :visited:hover ,
#side-bar a :visited:hover { 
color: var(--link-hover-txt-color) ;
text-decoration: none ;
background-color: var(--link-txt-color) ;
} 
a { 
transition-duration: 0.1 s ;
} 
/ * patch for sidebar media , collapsibles , ACS , info button and ayers module so link doesn ' t override * /
#page-content .collapsible-block-folded a :hover ,
#page-content .collapsible-block-unfolded-link a :hover ,
#page-content .rate-box-with-credit-button .fa-info :hover ,
#side-bar .side-block.media a :hover ,
.danger-diamond a :hover { 
background: transparent ;
} 
.info-container .collapsible-block-folded .collapsible-block-link ,
.info-container .collapsible-block-link { 
background: var(--linkColour) !important ;
} 
/ * MAIN > Header * /
div#header { 
background: none ;
height: 160 px ;
} 
#header h1 span ,
#header h2 span { 
font-size: 0 ;
display: none ;
} 
#header h1 a : :before ,
#header h2 : :before { 
color: var(--header-txt-color) ;
letter-spacing: 1 px ;
font-family: var(--head-font), sans-serif !important ;
font-weight: 900 ;
text-shadow: none ;
} 
#header h1 { 
margin-top: - 0.3 rem ;
} 
#header h1 a { 
width: fit-content ;
margin: auto ;
} 
#header h1 a : :before { 
content: var(--header-title) ;
font-size: 1.3 em ;
} 
#header h2 : :before { 
content: var(--header-subtitle) ;
font-family: var(--ui-font) !important ;
font-weight: 700 ;
font-size: 1.4 em ;
color: var(--misc-txt-color) ;
line-height: 26 px ;
margin-top: 0.35 rem ;
display: block ;
text-transform: uppercase ;
} 
#header h1 ,
#header h2 { 
margin-left: 0 ;
float: none ;
text-align: center ;
} 
#header h1 span ,
#header h2 span { 
font-size: 0 ;
display: none ;
} 
div#extra-div-1 { 
height: 160 px ;
width: 100 % ;
top: 7 px ;
position: absolute ;
background: var(--logo-img) 10 px 30 px no-repeat ;
background-size: 130 px ;
background-repeat: no-repeat ;
background-position: 50 % 50 % ;
z-index: - 1 ;
opacity: var(--logo-opacity) ;
} 
/ * MAIN > Header > Search Box * /
#search-top-box-form > input [ type = text ] { 
display: none ;
} 
#search-top-box-input ,
#search-top-box-input :hover ,
#search-top-box-input :focus ,
#search-top-box-form input [ type = submit ] ,
#search-top-box-form input [ type = submit ] :hover ,
#search-top-box-form input [ type = submit ] :focus { 
border: none ;
background: rgb(var(--accent)) ;
box-shadow: none ;
border-radius: 5 px !important ;
color: #efefef ;
font-family: var(--ui-font) ;
font-size: calc(var(--page-font-size) - 10 % ) ;
} 
#search-top-box input.empty { 
color: #999999 ;
} 
#search-top-box { 
position: absolute ;
top: 47 px ;
width: unset ;
} 
/ * MAIN > Header > Top Bar * /
#top-bar ,
#top-bar a { 
top: 10 rem ;
} 
#header #top-bar ul { 
border-radius: 10 px ;
border: none ;
background: rgb(var(--accent)) ;
padding-left: 15 px ;
padding-right: 15 px ;
} 
#header #top-bar a { 
color: white ;
background: rgb(var(--accent)) ;
font-weight: bold ;
} 
#header #top-bar ul li ul { 
padding: 0 px ;
border-radius: 0 px ;
} 
#top-bar ul li.sfhover a ,
#top-bar ul li :hover a { 
border-left: solid 1 px #FFF ;
border-right: solid 1 px #FFF ;
} 
#top-bar ul li ul li a :hover { 
color: rgba( 255 , 255 , 255 , 0.83 ) !important ;
line-height: 230 % ;
text-indent: 3 px ;
} 
#top-bar { 
display: flex ;
justify-content: center ;
right: 0 ;
} 
.mobile-top-bar { 
left: unset ;
} 
/ * MAIN > Header > Login Info * /
#login-status { 
top: 19 px ;
} 
#login-status ,
#login-status a { 
color: #333333 ;
} 
@media (max-width: 767 px ) { 
#header .printuser { 
font-size: 0 ;
} 
} 
.printuser a { 
margin: 0 ;
} 
.printuser img.small { 
width: 18 px ;
height: 18 px ;
padding: 1 px 4 px 0 0 ;
background-image: none !important ;
} 
@media (max-width: 767 px ) { 
#header .printuser img.small { 
transform: translate( 0 , 4 px ) ;
} 
} 
#my-account { 
display: none ;
} 
@media (max-width: 767 px ) { 
#account-topbutton { 
margin: 0 0 0 5 px ;
} 
} 
/ * MAIN > Header > Side Bar * /
#top-bar .open-menu a { 
border-radius: 0 px ;
border: none ;
background: rgb(var(--accent)) ;
color: white ;
} 
#side-bar { 
background: #FFF ;
} 
@media (min-width: 768 px ) { 
#side-bar { 
padding: 0.3 em 0.6 em 0 0.6 em ;
width: 18.75 em ;
transition: left 0.2 s ease-in-out ;
direction: rtl ;
text-align: left ;
border-right: none ;
} 
} 
#side-bar .side-block ,
#side-bar .side-block.resources ,
#side-bar .side-block.media ,
#interwiki .side-block { 
border: 2 px solid rgba( 0 , 0 , 0 , 0.2 ) ;
border-radius: 0 px ;
box-shadow: none ;
margin-bottom: 6 px ;
direction: ltr ;
background: transparent ;
} 
#side-bar .side-block.resources { 
text-align: center ;
} 
#side-bar .heading { 
color: var(--misc-txt-color) ;
border-bottom: solid 2 px #cfcfcf ;
font-size: 9 pt ;
font-family: var(--head-font) ;
font-weight: 800 ;
text-transform: uppercase ;
} 
/ * CONTENT * /
/ * CONTENT > Blockquotes , Custom Divs * /
.blockquote ,
div.blockquote ,
blockquote { 
border: solid 2 px rgba( 0 , 0 , 0 , 0.15 ) ;
background: #f7f7f7 ;
} 
.jotting { 
padding: 1.3 em ;
margin: 1 em 4.5 em ;
border: dashed 2 px rgba( 0 , 0 , 0 , 0.2 ) ;
background: #f7f7f7 ;
} 
.notation { 
padding: 1 em 1.5 em ;
margin: 1 em 3 em ;
border-left: solid 3 px rgba( 0 , 0 , 0 , 0.35 ) ;
border-right: solid 3 px rgba( 0 , 0 , 0 , 0.35 ) ;
background: #f7f7f7 ;
} 
.modal { 
padding: 1.2 em ;
margin: 1 em 3 em ;
border: solid 5 px rgba( 0 , 0 , 0 , 0.15 ) ;
background: #fbfbfb ;
} 
.quote { 
padding: 0.4 em 2 em ;
margin: 3 em auto ;
border-left: solid 3 px #bbb ;
